    function audio_wav_generator($mode = null, $frequency = null, $frequencies = null, $duration = null, $sample_rate = null, $bit_depth = null, $channels = null, $amplitude = null, $start_freq = null, $end_freq = null, $dtmf_digits = null, $dtmf_tone_duration = null, $dtmf_pause = null, $volume_ramp = null, $filename = null, $timeout = null)
