            '*' => [3,0], '0' => [3,1], '#' => [3,2], 'D' => [3,3],
        ];

        // Helper: volume envelope (anti-click)
        $envelope_fn = function($i, $num_samples, $sample_rate, $volume_ramp) {
            if ($volume_ramp <= 0) return 1.0;
            $ramp_samples = (int)round($sample_rate * $volume_ramp);
            if ($i < $ramp_samples) return $i / $ramp_samples;
            if ($i > $num_samples - $ramp_samples) return ($num_samples - $i) / $ramp_samples;
            return 1.0;
        };

        // Total number of PCM samples
        $num_samples = (int)round($sample_rate * $duration);
        $bytes_per_sample = $bit_depth / 8;
        $block_align = $channels * $bytes_per_sample;
        $byte_rate = $sample_rate * $block_align;
        $data_size = $num_samples * $block_align;
        $file_size = 36 + $data_size;

        // Build sample data
        $samples = [];

        if ($mode === 'dtmf') {
            $data_size = 0;
            for ($i = 0; $i < strlen($dtmf_digits); $i++) {
                $ch = strtoupper($dtmf_digits[$i]);
                if (!isset($dtmf_grid[$ch])) continue;
                $pos = $dtmf_grid[$ch];
                $f1 = $dtmf_rows[$pos[0]];
                $f2 = $dtmf_cols[$pos[1]];
                
                $tone_samples = (int)round($sample_rate * $dtmf_tone_duration);
                for ($t = 0; $t < $tone_samples; $t++) {
                    $phase = $t / $sample_rate;
                    $env = $envelope_fn($t, $tone_samples, $sample_rate, 0.002);
                    $val = (sin(2.0 * M_PI * $f1 * $phase) + sin(2.0 * M_PI * $f2 * $phase)) * 0.5 * $amplitude * $env;
                    $samples[] = $val;
                    $data_size += $block_align;
                }
                
                // Pause between tones
