                $frequencies = [261.63, 329.63, 392.00];
            }
            $fs = count($frequencies);
            for ($i = 0; $i < $num_samples; $i++) {
                $phase = $i / $sample_rate;
                $val = 0.0;
                foreach ($frequencies as $f) {
                    $val += sin(2.0 * M_PI * $f * $phase);
                }
