                $env = $envelope_fn($i, $num_samples, $sample_rate, $volume_ramp);
                $samples[] = $val * $amplitude * $env;
            }
        } elseif ($mode === 'sawtooth') {
            for ($i = 0; $i < $num_samples; $i++) {
                $period = $sample_rate / $frequency;
                $phase = ($i / $period);
                $phase_frac = $phase - floor($phase);
                $val = 2.0 * $phase_frac - 1.0;
                $env = $envelope_fn($i, $num_samples, $sample_rate, $volume_ramp);
                $samples[] = $val * $amplitude * $env;
            }
        } elseif ($mode === 'triangle') {
            for ($i = 0; $i < $num_samples; $i++) {
                $period = $sample_rate / $frequency;
                $phase = ($i / $period);
                $phase_frac = $phase - floor($phase);
                $val = 4.0 * abs($phase_frac - 0.5) - 1.0;
                $env = $envelope_fn($i, $num_samples, $sample_rate, $volume_ramp);
                $samples[] = $val * $amplitude * $env;
            }
        } elseif ($mode === 'noise_white') {
            for ($i = 0; $i < $num_samples; $i++) {
